"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[34242],{76086:(e,n,a)=>{a.r(n),a.d(n,{data:()=>s});const s={key:"v-ca44cd9a",path:"/nodejs/%E5%8C%85%E7%AE%A1%E7%90%86/yarn/",title:"Yarn",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"参考资料",slug:"参考资料",children:[]},{level:2,title:"工作区",slug:"工作区",children:[{level:3,title:"如何使用工作区",slug:"如何使用工作区",children:[]},{level:3,title:"限制和警告",slug:"限制和警告",children:[]}]},{level:2,title:"其他",slug:"其他",children:[]}],git:{updatedTime:1653451151e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"nodejs/包管理/yarn/README.md"}},41286:(e,n,a)=>{a.r(n),a.d(n,{default:()=>h});var s=a(57293);const i=(0,s.uE)('<h1 id="yarn" tabindex="-1"><a class="header-anchor" href="#yarn" aria-hidden="true">#</a> Yarn</h1><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2><p>中文文档:https://www.bookstack.cn/read/yarn-cn/0.md</p><p>https://www.yarnpkg.cn/</p><p>工作区(博客):https://blog.csdn.net/ivenqin/article/details/118522135</p><h2 id="工作区" tabindex="-1"><a class="header-anchor" href="#工作区" aria-hidden="true">#</a> 工作区</h2>',6),r=(0,s.Uk)("本节我们学习 "),d={href:"https://so.csdn.net/so/search?q=Yarn&spm=1001.2101.3001.7020",target:"_blank",rel:"noopener noreferrer"},l=(0,s.Uk)("Yarn"),t=(0,s.Uk)(" 工作区，什么是工作区呢？ 工作区是设置软件包体系结构的一种新方式，默认情况下从 Yarn 1.0 开始使用。我们可以使用这种方式安装多个软件包， 也就是只需要执行一次 yarn install 命令便可以将所有依赖包全部安装。"),o=(0,s._)("h3",{id:"如何使用工作区",tabindex:"-1"},[(0,s._)("a",{class:"header-anchor",href:"#如何使用工作区","aria-hidden":"true"},"#"),(0,s.Uk)(" 如何使用工作区")],-1),c=(0,s.Uk)("在 package.json 文件中添加以下内容，接下来我们将此目录称为 “工作区"),u={href:"https://so.csdn.net/so/search?q=%E6%A0%B9%E7%9B%AE%E5%BD%95&spm=1001.2101.3001.7020",target:"_blank",rel:"noopener noreferrer"},v=(0,s.Uk)("根目录"),p=(0,s.Uk)("”："),b=(0,s.uE)('<div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code>{\n    &quot;private&quot;: true,\n    &quot;workspaces&quot;: [&quot;workspace-a&quot;, &quot;workspace-b]\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中 private:true 是必填项，工作区并不是要发布的，因为添加了此安全措施来确保没有任何东西可以意外地暴露它们。</p><p>创建这个文件之后，我们需要在创建两个新的子文件夹：workspace-a 和 workspace-b。在每个文件夹里面，创建一个具有以下内容的 package. json 文件： workspace-a/package.json：</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code>{\n  &quot;name&quot;: &quot;workspace-a&quot;,\n  &quot;version&quot;: &quot;1.0.0&quot;,\n\n  &quot;dependencies&quot;: {\n    &quot;cross-env&quot;: &quot;5.0.5&quot;\n  }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>workspace-b/package.json：</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code>{\n    &quot;name&quot;: &quot;workspace-b&quot;,\n    &quot;version&quot;: &quot;1.0.0&quot;,\n    \n    &quot;dependencies&quot;: {\n        &quot;cross-env&quot;: &quot;5.0.5&quot;,\n        &quot;workspace-a&quot;: &quot;1.0.0&quot;\n    }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>最后可以在工作区根目录中执行 yarn install 命令，如果一切正常，现在应该有一个类似下面这样的文件层次结构：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>/package.json\n/yarn.lock\n\n/node_modules\n/node_modules/cross-env\n/node_modules/workspace-a -&gt; /workspace-a\n\n/workspace-a/package.json\n/workspace-b/package.json\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>workspace-b 需要一个在 workspace-a 中的文件，现在将直接使用当前项目内部的文件，而不是从 Github 上面获取。cross-env 包已正确去重并放在项目的根目录下，让 workspace-a 和 workspace-b可以一起使用这个包。</p><h3 id="限制和警告" tabindex="-1"><a class="header-anchor" href="#限制和警告" aria-hidden="true">#</a> 限制和警告</h3><ul><li>包层级在工作区和用户得到的内容之间将有所不同（工作区依赖将提升到文件系统层次结构中）。 对这个层级的假设已经是危险的，因为提升过程不是标准化的，所以理论上没有什么新东西。</li><li>在上面的示例中，如果 workspace-b 依赖于 workspace-a 的包，但是引用的是不同的版本，那么依赖包将从 Github 安装，而不是从本地文件系统链接。 这是因为一些软件包实际上需要使用以前的版本，以建立新的版本（Babel 是其中之一）。</li><li>在工作区中发布包时要留心。 如果你正准备发布下一个版本，并且你决定引用一个新依赖但忘了在 package.json 中声明，你的测试仍可能在本地通过（如果其他包已经把那个引用下载到了项目根目录）。 然而其他从源中拉取包的用户就不行了，由于依赖列表现在是不完整的，他们没办法下载那个新依赖。 目前没有办法在这种情况下抛出警告。</li><li>工作区必须是项目根目录的子目录，我们不能也不应当引用位于项目目录之外的工作区。 工作区不支持嵌套。</li></ul><h2 id="其他" tabindex="-1"><a class="header-anchor" href="#其他" aria-hidden="true">#</a> 其他</h2><p>速度优化</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>yarn config set registry https://registry.npm.taobao.org -g\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>yarn config set sass_binary_site http://cdn.npm.taobao.org/dist/node-sass -g\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>不行再搞上这句</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>yarn config set ignore-engines true\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>清理本地缓存</p><p>yarn cache clean</p><p>查找目录</p><p>yarn cache dir</p><p>查看当前registry <code>yarn config get registry</code> 修改registry为特定的链接( 下方时修改为淘宝的源)</p><p><code>yarn config set registry https://registry.npm.taobao.org</code></p>',23),m={},h=(0,a(63243).Z)(m,[["render",function(e,n){const a=(0,s.up)("ExternalLinkIcon");return(0,s.wg)(),(0,s.iD)(s.HY,null,[i,(0,s._)("p",null,[r,(0,s._)("a",d,[l,(0,s.Wm)(a)]),t]),o,(0,s._)("p",null,[c,(0,s._)("a",u,[v,(0,s.Wm)(a)]),p]),b],64)}]])},63243:(e,n)=>{n.Z=(e,n)=>{const a=e.__vccOpts||e;for(const[e,s]of n)a[e]=s;return a}}}]);